use std::collections::HashMap;
use std::hash::Hash;

struct Cache<K: Hash + Eq, V> { data: HashMap<K, V>, order: Vec<K>, capacity: usize }

impl<K: Hash + Eq + Clone, V> Cache<K, V> {
    pub fn new(capacity: usize) -> Self { Self { data: HashMap::new(), order: Vec::new(), capacity } }
    pub fn get(&self, key: &K) -> Option<&V> { self.data.get(key) }
    pub fn insert(&mut self, key: K, value: V) {
        if self.data.contains_key(&key) {
            self.data.insert(key, value);
        } else {
            if self.order.len() >= self.capacity {
                let oldest = self.order.remove(0);
                self.data.remove(&oldest);
            }
            self.order.push(key.clone());
            self.data.insert(key, value);
        }
    }
    pub fn evict_oldest(&mut self) -> Option<V> {
        if self.order.is_empty() { None }
        else { let k = self.order.remove(0); self.data.remove(&k) }
    }
    pub fn len(&self) -> usize { self.data.len() }
}

