struct Range { current: i32, end: i32 }

impl Range {
    pub fn new(start: i32, end: i32) -> Self { Self { current: start, end } }
}

impl Iterator for Range {
    type Item = i32;
    fn next(&mut self) -> Option<i32> {
        if self.current < self.end {
            let val = self.current;
            self.current += 1;
            Some(val)
        } else { None }
    }
}

pub fn collect_range(start: i32, end: i32) -> Vec<i32> {
    let mut range = Range::new(start, end);
    let mut result = Vec::new();
    while let Some(val) = range.next() { result.push(val); }
    result
}

