S Config {
    host: s,
    port: u16,
    max_connections: u32,
    tls: bool,
}

S ConfigBuilder {
    host: ?s,
    port: ?u16,
    max_connections: ?u32,
    tls: ?bool,
}

I ConfigBuilder {
    +f new() -> ConfigBuilder {
        @ConfigBuilder {
            host: ?None, port: ?None,
            max_connections: ?None, tls: ?None,
        }
    }
    +f host(!self, host: s) -> ConfigBuilder {
        self.host = ?Some(host);
        self
    }
    +f port(!self, port: u16) -> ConfigBuilder {
        self.port = ?Some(port);
        self
    }
    +f max_connections(!self, max: u32) -> ConfigBuilder {
        self.max_connections = ?Some(max);
        self
    }
    +f tls(!self, enabled: bool) -> ConfigBuilder {
        self.tls = ?Some(enabled);
        self
    }
    +f build(self) -> R[Config, s] {
        v host = self.host.ok_or("host is required")?;
        v port = self.port.unwrap_or(8080);
        v max_conn = self.max_connections.unwrap_or(100);
        v tls = self.tls.unwrap_or(0b);
        R.Ok(@Config {
            host: host, port: port,
            max_connections: max_conn, tls: tls,
        })
    }
}

