struct Config { host: String, port: u16, max_connections: u32, tls: bool }

struct ConfigBuilder { host: Option<String>, port: Option<u16>, max_connections: Option<u32>, tls: Option<bool> }

impl ConfigBuilder {
    pub fn new() -> Self { Self { host: None, port: None, max_connections: None, tls: None } }
    pub fn host(mut self, host: String) -> Self { self.host = Some(host); self }
    pub fn port(mut self, port: u16) -> Self { self.port = Some(port); self }
    pub fn max_connections(mut self, max: u32) -> Self { self.max_connections = Some(max); self }
    pub fn tls(mut self, enabled: bool) -> Self { self.tls = Some(enabled); self }
    pub fn build(self) -> Result<Config, String> {
        let host = self.host.ok_or("host is required")?;
        Ok(Config {
            host, port: self.port.unwrap_or(8080),
            max_connections: self.max_connections.unwrap_or(100),
            tls: self.tls.unwrap_or(false),
        })
    }
}
